 91→    private fun loadProfiles() {
 92→        lifecycleScope.launch {
 93→            profiles.clear()
 94→            profiles.addAll(db.profileDao().getAll())
 95→            if (profiles.isEmpty()) {
 96→                val id = db.profileDao().insert(Profile(name = "默认档案"))
 97→                profiles.add(Profile(id = id, name = "默认档案"))
 98→            }
 99→            spProfile.adapter = ArrayAdapter(
100→                this@MainActivity, android.R.layout.simple_spinner_dropdown_item,
101→                profiles.map { it.name }
102→            )
103→            loadFields()
104→        }
105→    }
106→
107→    private fun loadFields() {
108→        val pid = currentProfileId ?: return
109→        lifecycleScope.launch {
110→            fields.clear()
111→            fields.addAll(db.fieldDao().getByProfile(pid))
112→            rvFields.adapter = FieldRowAdapter(fields,
113→                onDelete = { f ->
114→                    lifecycleScope.launch {
115→                        db.fieldDao().delete(f)
116→                        fields.remove(f)
117→                        rvFields.adapter?.notifyDataSetChanged()
118→                    }
119→                }
120→            )
121→        }
122→    }
123→
124→    private fun addProfile() {
125→        val et = EditText(this).apply { hint = "档案名称" }
126→        AlertDialog.Builder(this).setTitle("新建档案").setView(et)
127→            .setPositiveButton("确定") { _, _ ->
128→                val name = et.text.toString().trim()
129→                if (name.isNotEmpty()) {
130→                    lifecycleScope.launch {
131→                        db.profileDao().insert(Profile(name = name))
132→                        loadProfiles()
133→                    }
134→                }
135→            }.show()
136→    }
137→
138→    private fun deleteProfile() {
139→        val p = profiles.getOrNull(spProfile.selectedItemPosition) ?: return
140→        if (profiles.size <= 1) {
141→            Toast.makeText(this, "至少保留一个档案", Toast.LENGTH_SHORT).show()
142→            return
143→        }
144→        AlertDialog.Builder(this).setTitle("删除档案「${p.name}」？")
145→            .setPositiveButton("删除") { _, _ ->
146→                lifecycleScope.launch {
147→                    db.profileDao().delete(p)
148→                    loadProfiles()
149→                }
150→            }.setNegativeButton("取消", null).show()
151→    }
152→
153→    private fun extractFields() {
154→        val text = etInput.text.toString().trim()
155→        if (text.isEmpty()) {
156→            Toast.makeText(this, "请先输入或粘贴文本", Toast.LENGTH_SHORT).show()
157→            return
158→        }
159→        val pid = currentProfileId ?: return
160→        val extracted = FieldExtractor.extract(text)
161→        if (extracted.isEmpty()) {
162→            Toast.makeText(this, "未提取到字段", Toast.LENGTH_SHORT).show()
163→            return
164→        }
165→        lifecycleScope.launch {
166→            val newFields = extracted.map { Field(profileId = pid, label = it.label, value = it.value, fieldType = it.type) }
167→            db.fieldDao().insertAll(newFields)
168→            loadFields()
169→            Toast.makeText(this@MainActivity, "提取了 ${newFields.size} 个字段", Toast.LENGTH_SHORT).show()
170→        }
171→    }
172→
173→    private fun addField() {
174→        val label = etLabel.text.toString().trim()
175→        val value = etValue.text.toString().trim()
176→        if (label.isEmpty() || value.isEmpty()) return
177→        val pid = currentProfileId ?: return
178→        lifecycleScope.launch {
179→            db.fieldDao().insert(Field(profileId = pid, label = label, value = value))
180→            etLabel.text.clear()
181→            etValue.text.clear()
182→            loadFields()
183→        }
184→    }
185→}
